#include <bits/stdc++.h>
using namespace std;
void init(int, int);
void report(int c);
void invert(std::vector<int>);


const int N=510;

struct Node{
    int a,b,c;
};

bool g[N][N];

void init(int c, int t) {
    return;
}

void starmap(int n, int m, int k, int p, std::vector<int> u,
    std::vector<int> v) {
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            g[i][j]=(i!=j);
    for(int i=0;i<m;i++)
         g[u[i]][v[i]]=g[v[i]][u[i]]=0;
    vector<Node> r;
    r.clear();
    for(int i=1;i<=n;i++){
        int lst=0;
        for(int j=1;j<=n;j++){
            if(g[i][j] && lst){
                g[i][j]=g[j][i]=g[i][lst]=g[lst][i]=0;
                g[j][lst]^=1;
                g[lst][j]^=1;
                r.push_back((Node){i,j,lst});
                lst=0;
            }else if(g[i][j])
                lst=j;
        }
    }
    int ans=0;
    for(int i=1;i<=n;i++)
        for(int j=i+1;j<=n;j++)
            if(!g[i][j])
                ans++;
    report(ans);
    vector<int> s;
    for(Node i:r){
        s.clear();
        s.push_back(i.a);
        s.push_back(i.b);
        s.push_back(i.c);
        invert(s);
    }
}
